VALUES
  ('elementary-0a2fc18c-moex-00723', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '依民法第758條第1項規定，不動產物權行為以登記為要件。關於不動產物權行為，下列敘述，何者錯 誤？', '["不動產物權行為以登記為公示手段", "不動產物權行為之登記乃宣示登記", "不動產物權行為應以書面為之", "不動產物權行為不以交付不動產為要件"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00724', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '稱動產質權者，謂債權人對於債務人或第三人移轉占有而供其債權擔保之動產，得就該動產賣得價金優 先受償之權。關於質權人之權利，下列敘述，何者錯誤？', '["質權人得占有質物", "質權人得使用質物", "質權人得請求無權占有質物者，返還質物於自己", "質權人於債權已屆清償期，而未受清償者，得拍賣質物"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00725', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '關於夫妻共同收養子女，下列敘述，何者錯誤？', '["夫妻不得收養其直系血親為養子女", "夫妻之一方收養他方之親生子女，無須夫妻共同為之", "夫妻之一方於婚前有收養子女者，婚後，他方必須收養該名養子女", "夫妻之一方不能為意思表示或生死不明已逾3年者，他方得單獨收養子女"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00726', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '依民法規定，下列何者無法對受婚生推定之子女提起婚生否認之訴？', '["受婚生推定之夫", "生母", "曾祖父母", "該子女本人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00727', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '甲立遺囑遺贈其所有之房屋一棟於乙。惟該房屋因丙之過失致毀損滅失。一年後，甲死亡。下列敘述， 何者正確？', '["消滅時效已完成，乙不得向丙請求損害賠償", "房屋已毀損滅失，不屬於遺產，遺贈無效", "推定以甲對丙之損害賠償請求權為遺贈", "乙得向甲之繼承人請求債務不履行之損害賠償"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00728', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列關於偵查中羈押之敘述，何者正確？', '["被告犯罪嫌疑重大，檢察官即可羈押", "被告涉嫌公然侮辱罪，檢察官亦可羈押", "如果被告有反覆實行同一竊盜犯罪之高度可能性，法院可裁定羈押", "即使被告有勾串共犯的可能，法院也不可以裁定羈押"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
