  ('elementary-0a2fc18c-moex-00730', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列關於嚴格證明法則之敘述，何者錯誤？', '["嚴格證明與自由證明並不相同", "嚴格證明法則涉及證據能力及有無經合法調查證據之程序", "犯罪事實存在之認定需要嚴格之證明", "自由證明與自由心證之意義相同"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
